mapper.update:
update dy_live_room
room_name = #{roomName}, source = #{source}, status = #{status}, remark = #{remark}, update_time = sysdate()
where room_key = #{roomKey}

mapper.select:
select lead_id
from dy_viewer_daily_lead
where lead_date = #{leadDate}
  and room_key = #{roomKey}
  and sec_uid = #{secUid}
limit 1

mapper.update:
update dy_viewer_daily_lead
set douyin_user_id = #{douyinUserId},
    live_room_name = #{liveRoomName},
    viewer_id = #{viewerId},
    nickname = #{nickname},
    avatar = #{avatar},
    update_time = sysdate()
where lead_date = #{leadDate}
  and room_key = #{roomKey}
  and sec_uid = #{secUid}

mapper.select:
select lead_id, viewer_id, sec_uid
from dy_viewer_daily_lead
where lead_date = #{leadDate}
  and room_key = #{roomKey}
  and nickname = #{nickname}
order by update_time desc
limit 1

mapper.update:
update dy_viewer_comment
set lead_id = #{leadId},
    viewer_id = #{viewerId},
    match_type = 'nickname'
where lead_id is null
  and lead_date = #{leadDate}
  and room_key = #{roomKey}
  and nickname = #{nickname}

mapper.select:
select
    l.lead_id, l.lead_date, l.room_key, l.douyin_user_id,
    coalesce(nullif(r.room_name, ''), nullif(l.live_room_name, ''), l.room_key) as live_room_name,
    l.viewer_id, l.sec_uid, l.nickname, l.avatar, l.has_comment, l.comment_count,
    l.first_comment_time, l.last_comment_time, l.last_comment_content, l.status,
    l.intent, l.owner_id, l.owner_name, l.owner_assigned_time, l.order_no, l.remark,
    l.last_follow_time, l.next_follow_time, l.manual_update_time, l.create_time, l.update_time
from dy_viewer_daily_lead l
left join dy_live_room r on r.room_key = l.room_key


        and l.lead_date = #{leadDate}


        and l.room_key = #{roomKey}


        and coalesce(r.room_name, l.live_room_name, l.room_key) like concat('%', #{roomName}, '%')


        and l.nickname like concat('%', #{nickname}, '%')


        and l.has_comment = #{hasComment}


        and l.status = #{status}


        and l.intent = #{intent}


        and l.owner_id = #{ownerId}


        and l.order_no like concat('%', #{orderNo}, '%')


order by l.has_comment desc, l.last_comment_time desc, l.update_time desc

mapper.update:
update dy_viewer_daily_lead
status = #{status}, intent = #{intent}, owner_id = #{ownerId}, owner_name = nullif(#{ownerName}, ''), owner_assigned_time = #{ownerAssignedTime}, order_no = #{orderNo}, remark = #{remark}, manual_update_time = sysdate(), update_time = sysdate()
where lead_id = #{leadId}

mapper.select:
select count(1) as totalCount, sum(case when l.has_comment = 1 then 1 else 0 end) as commentLeadCount, sum(case when l.status = 'new' then 1 else 0 end) as newCount, sum(case when l.status = 'following' then 1 else 0 end) as followingCount, sum(case when l.status = 'ordered' then 1 else 0 end) as orderedCount, max(l.update_time) as lastUpdateTime from dy_viewer_daily_lead l left join dy_live_room r on r.room_key = l.room_key
and l.lead_date = #{leadDate}
and l.room_key = #{roomKey}
and coalesce(r.room_name, l.live_room_name, l.room_key) like concat('%', #{roomName}, '%')
